<template>
	<view class="search-container">
		<!-- жҗңзҙўжЎҶ -->
		<view class="search-bar">
			<view class="search-box">
				<u-icon name="search" size="36" color="#999"></u-icon>
				<input class="search-input" type="text" v-model="searchText" placeholder="жҗңзҙўжӯҢжӣІгҖҒжӯҢжүӢгҖҒдё“иҫ‘гҖҒжӯҢиҜҚ" 
					confirm-type="search" @confirm="handleSearch" @input="handleInput"/>
				<u-icon v-if="searchText" name="close" size="36" color="#999" @click="clearSearch"></u-icon>
			</view>
			<text class="cancel-btn" @click="goBack">еҸ–ж¶Ҳ</text>
		</view>
		
		<!-- жҗңзҙўеҺҶеҸІ -->
		<view class="search-history" v-if="!searchText && searchHistory.length > 0">
			<view class="history-header">
				<text class="title">жҗңзҙўеҺҶеҸІ</text>
				<u-icon name="trash" size="32" color="#999" @click="clearHistory"></u-icon>
			</view>
			<view class="history-list">
				<view class="history-item" v-for="(item, index) in searchHistory" :key="index" @click="useHistoryItem(item)">
					<text>{{item}}</text>
				</view>
			</view>
		</view>
		
		<!-- зғӯй—ЁжҗңзҙўиҜҚ -->
		<view class="hot-search" v-if="!searchText && hotSearch.length > 0">
			<view class="hot-header">
				<text class="title">зғӯй—Ёжҗңзҙў</text>
			</view>
			<view class="hot-list">
				<view class="hot-item" v-for="(item, index) in hotSearch" :key="index" @click="useHistoryItem(item)">
					<text>{{item}}</text>
				</view>
			</view>
		</view>
		
		<!-- жҗңзҙўз»“жһң -->
		<view class="search-results" v-if="searchText && hasSearched">
			<!-- жІЎжңүжҗңзҙўз»“жһң -->
			<view class="no-result" v-if="noResults">
				<text>жҡӮж— жҗңзҙўз»“жһң</text>
			</view>
			
			<!-- з»“жһңж ҮзӯҫйЎө -->
			<view class="result-tabs" v-else>
				<view class="tab-header">
					<view class="tab-item" 
						v-for="(tab, index) in tabs" 
						:key="index" 
						:class="{'active': currentTab === index}"
						@click="switchTab(index)">
						<text>{{tab.name}}({{tab.count || 0}})</text>
					</view>
				</view>
				
				<!-- жӯҢжӣІеҲ—иЎЁ -->
				<scroll-view
					v-if="currentTab === 0"
					class="tab-content-scroll"
					scroll-y="true"
					@scrolltolower="loadMoreSongs"
					lower-threshold="50"
					enable-back-to-top
					scroll-anchoring
				>
					<view class="tab-content">
						<view class="song-item" v-for="(song, index) in searchResults.songs" :key="song.id+index">
							<view class="song-info" @tap.stop="handleSongTap(song)">
								<text class="song-name">{{song.name}}</text>
								<text class="song-artist">{{song.artist}}</text>
							</view>
							<view class="song-actions">
								<text v-if="fromPlaylist" class="add-icon" @tap.stop="addSongToPlaylist(song)">
									<text v-if="song.isAdding" class="loading-dots">ж·»еҠ дёӯ</text>
									<text v-else class="iconfont icon-add"></text>
								</text>
								<view @tap.stop="playSong(song)">
									<u-icon name="play-right" size="36" color="#999"></u-icon>
								</view>
							</view>
						</view>
						
						<!-- еҠ иҪҪзҠ¶жҖҒжҸҗзӨә -->
						<view class="loading-status" v-if="searchResults.songs.length > 0">
							<view v-if="isLoadingMore.songs" class="loading-more">
								<view class="loading-spinner"></view>
								<text>жӯЈеңЁеҠ иҪҪжӣҙеӨҡжӯҢжӣІ...</text>
							</view>
							<text v-else-if="hasMore.songs">еҗ‘дёӢж»‘еҠЁеҠ иҪҪжӣҙеӨҡ</text>
							<text v-else>е·ІеҠ иҪҪе…ЁйғЁжӯҢжӣІ</text>
						</view>
					</view>
				</scroll-view>
				
				<!-- жӯҢжүӢеҲ—иЎЁ -->
				<scroll-view
					v-if="currentTab === 1"
					class="tab-content-scroll"
					scroll-y="true"
					@scrolltolower="loadMoreArtists"
					lower-threshold="50"
					enable-back-to-top
					scroll-anchoring
				>
					<view class="tab-content">
						<view class="artist-item" v-for="(artist, index) in searchResults.artists" :key="artist.id+index" @click="viewArtist(artist)">
						<image class="artist-avatar" :src="artist.avatar || '/static/music-cover.png'" mode="aspectFill"></image>
						<text class="artist-name">{{artist.name}}</text>
					</view>
						
						<!-- еҠ иҪҪзҠ¶жҖҒжҸҗзӨә -->
						<view class="loading-status" v-if="searchResults.artists.length > 0">
							<text v-if="isLoadingMore.artists">жӯЈеңЁеҠ иҪҪжӣҙеӨҡжӯҢжүӢ...</text>
							<text v-else-if="hasMore.artists">еҗ‘дёӢж»‘еҠЁеҠ иҪҪжӣҙеӨҡ</text>
							<text v-else>е·ІеҠ иҪҪе…ЁйғЁжӯҢжүӢ</text>
					</view>
				</view>
				</scroll-view>
				
				<!-- дё“иҫ‘еҲ—иЎЁ -->
				<scroll-view
					v-if="currentTab === 2"
					class="tab-content-scroll"
					scroll-y="true"
					@scrolltolower="loadMoreAlbums"
					lower-threshold="50"
					enable-back-to-top
					scroll-anchoring
				>
					<view class="tab-content">
						<view class="album-item" v-for="(album, index) in searchResults.albums" :key="album.id+index" @click="viewAlbum(album)">
						<image class="album-cover" :src="album.cover || '/static/music-cover.png'" mode="aspectFill"></image>
						<view class="album-info">
							<text class="album-name">{{album.name}}</text>
							<text class="album-artist">{{album.artist}}</text>
						</view>
					</view>
						
						<!-- еҠ иҪҪзҠ¶жҖҒжҸҗзӨә -->
						<view class="loading-status" v-if="searchResults.albums.length > 0">
							<text v-if="isLoadingMore.albums">жӯЈеңЁеҠ иҪҪжӣҙеӨҡдё“иҫ‘...</text>
							<text v-else-if="hasMore.albums">еҗ‘дёӢж»‘еҠЁеҠ иҪҪжӣҙеӨҡ</text>
							<text v-else>е·ІеҠ иҪҪе…ЁйғЁдё“иҫ‘</text>
						</view>
					</view>
				</scroll-view>
				
				<!-- жӯҢиҜҚеҲ—иЎЁ -->
				<scroll-view
					v-if="currentTab === 3"
					class="tab-content-scroll"
					scroll-y="true"
					@scrolltolower="loadMoreLyrics"
					lower-threshold="50"
					enable-back-to-top
					scroll-anchoring
				>
					<view class="tab-content">
						<view class="lyrics-item" v-for="(item, index) in searchResults.lyrics" :key="item.id+index" @click="playSong(item)">
							<view class="lyrics-info">
								<text class="lyrics-content">{{item.lyrics || 'жҡӮж— жӯҢиҜҚ'}}</text>
								<view class="lyrics-song-info">
									<text class="lyrics-song-name">{{item.name}}</text>
									<text class="lyrics-song-artist">- {{item.artist}}</text>
								</view>
							</view>
							<view>
								<u-icon name="play-right" size="36" color="#999"></u-icon>
							</view>
						</view>
						
						<!-- еҠ иҪҪзҠ¶жҖҒжҸҗзӨә -->
						<view class="loading-status" v-if="searchResults.lyrics.length > 0">
							<text v-if="isLoadingMore.lyrics">жӯЈеңЁеҠ иҪҪжӣҙеӨҡжӯҢиҜҚ...</text>
							<text v-else-if="hasMore.lyrics">еҗ‘дёӢж»‘еҠЁеҠ иҪҪжӣҙеӨҡ</text>
							<text v-else>е·ІеҠ иҪҪе…ЁйғЁжӯҢиҜҚ</text>
					</view>
				</view>
				</scroll-view>
			</view>
		</view>
	</view>
</template>

<script>
	import { getMusicUrl, getMusicById, searchMusic, isInGuestMode, showGuestModeLimit } from '@/utils/musicData.js'
	import apiConfig from '@/utils/apiConfig.js'
	import request from '@/utils/request.js'
	
	export default {
		data() {
			return {
				searchText: '',
				searchHistory: [],
				hotSearch: ['е‘Ёжқ°дјҰ', 'жһ—дҝҠжқ°', 'и–ӣд№Ӣи°Ұ', 'йҷҲеҘ•иҝ…', 'иө·йЈҺдәҶ', 'зғӯзҲұ105В°Cзҡ„дҪ '],
				hasSearched: false,
				isSearching: false,
				searchResults: {
					songs: [],
					artists: [],
					albums: [],
					lyrics: []
				},
				currentTab: 0,
				tabs: [
					{ name: 'еҚ•жӣІ', count: 0 },
					{ name: 'жӯҢжүӢ', count: 0 },
					{ name: 'дё“иҫ‘', count: 0 },
					{ name: 'жӯҢиҜҚ', count: 0 }
				],
				// еҲҶйЎөеҠ иҪҪзӣёе…і
				pageSize: 20, // жҜҸйЎөж•°йҮҸ
				pageOffset: {
					songs: 0,
					artists: 0,
					albums: 0,
					lyrics: 0
				},
				hasMore: {
					songs: false,
					artists: false,
					albums: false,
					lyrics: false
				},
				isLoadingMore: {
					songs: false,
					artists: false,
					albums: false,
					lyrics: false
				},
				totalCount: {
					songs: 0,
					artists: 0,
					albums: 0,
					lyrics: 0
				},
				fromPlaylist: false,
				playlistId: '',
				addingToPlaylist: false
			}
		},
		computed: {
			noResults() {
				return this.hasSearched && 
					this.searchResults.songs.length === 0 && 
					this.searchResults.artists.length === 0 && 
					this.searchResults.albums.length === 0 &&
					this.searchResults.lyrics.length === 0
			}
		},
		onLoad(options) {
			// жЈҖжҹҘжҳҜеҗҰдёәжёёе®ўжЁЎејҸ
			if (isInGuestMode()) {
				// жҳҫзӨәжҸҗзӨә
				showGuestModeLimit('жҗңзҙўйҹід№җ');
				// иҝ”еӣһдёҠдёҖйЎө
				setTimeout(() => {
					uni.navigateBack();
				}, 1500);
				return;
			}
			
			// еҠ иҪҪжҗңзҙўеҺҶеҸІ
			this.loadSearchHistory()
			
			// жЈҖжҹҘжҳҜеҗҰд»Һж’ӯж”ҫеҲ—иЎЁйЎөйқўи·іиҪ¬иҝҮжқҘ
			if (options.from === 'playlist' && options.playlistId) {
				this.fromPlaylist = true
				this.playlistId = options.playlistId
				console.log('д»Һж’ӯж”ҫеҲ—иЎЁйЎөйқўи·іиҪ¬иҝҮжқҘпјҢж’ӯж”ҫеҲ—иЎЁIDпјҡ', this.playlistId)
			} else {
				this.fromPlaylist = false
				this.playlistId = ''
			}
			
			// и®ҫзҪ®з„ҰзӮ№
			this.$nextTick(() => {
				// иҮӘеҠЁиҒҡз„ҰжҗңзҙўжЎҶпјҢе»¶иҝҹжү§иЎҢзЎ®дҝқз»„д»¶е·ІеҠ иҪҪ
				setTimeout(() => {
					const inputEl = uni.createSelectorQuery().in(this).select('#searchInput')
					if (inputEl) {
						inputEl.boundingClientRect(data => {
							if (data) {
								uni.showKeyboard()
							}
						}).exec()
					}
				}, 300)
			})
		},
		methods: {
			// еҠ иҪҪжҗңзҙўеҺҶеҸІ
			loadSearchHistory() {
				try {
					const history = uni.getStorageSync('searchHistory')
					if (history) {
						this.searchHistory = JSON.parse(history)
					}
				} catch (error) {
					console.error('еҠ иҪҪжҗңзҙўеҺҶеҸІеӨұиҙҘпјҡ', error)
				}
			},
			
			// дҝқеӯҳжҗңзҙўеҺҶеҸІ
			saveSearchHistory(keyword) {
				try {
					// еҰӮжһңе·ІеӯҳеңЁпјҢе…Ҳз§»йҷӨ
					const index = this.searchHistory.indexOf(keyword)
					if (index > -1) {
						this.searchHistory.splice(index, 1)
					}
					
					// ж·»еҠ еҲ°ејҖеӨҙ
					this.searchHistory.unshift(keyword)
					
					// еҸӘдҝқз•ҷ10жқЎеҺҶеҸІи®°еҪ•
					if (this.searchHistory.length > 10) {
						this.searchHistory = this.searchHistory.slice(0, 10)
					}
					
					// дҝқеӯҳеҲ°жң¬ең°еӯҳеӮЁ
					uni.setStorageSync('searchHistory', JSON.stringify(this.searchHistory))
				} catch (error) {
					console.error('дҝқеӯҳжҗңзҙўеҺҶеҸІеӨұиҙҘпјҡ', error)
				}
			},
			
			// жё…з©әжҗңзҙўеҺҶеҸІ
			clearHistory() {
				uni.showModal({
					title: 'жҸҗзӨә',
					content: 'зЎ®е®ҡиҰҒжё…з©әжҗңзҙўеҺҶеҸІеҗ—пјҹ',
					success: (res) => {
						if (res.confirm) {
							this.searchHistory = []
							uni.setStorageSync('searchHistory', JSON.stringify([]))
						}
					}
				})
			},
			
			// дҪҝз”ЁеҺҶеҸІи®°еҪ•йЎ№
			useHistoryItem(keyword) {
				this.searchText = keyword
				this.handleSearch()
			},
			
			// жё…з©әжҗңзҙўжЎҶ
			clearSearch() {
				this.searchText = ''
				this.hasSearched = false
			},
			
			// еӨ„зҗҶиҫ“е…ҘдәӢд»¶
			handleInput(e) {
				// еҸҜд»ҘеңЁиҝҷйҮҢе®һзҺ°иҫ“е…Ҙе»әи®®
				console.log('иҫ“е…Ҙпјҡ', this.searchText)
			},
			
			// еӨ„зҗҶжҗңзҙўдәӢд»¶
			async handleSearch() {
				if (!this.searchText.trim()) return;
				
				// жЈҖжҹҘжҳҜеҗҰдёәжёёе®ўжЁЎејҸ
				if (isInGuestMode()) {
					showGuestModeLimit('жҗңзҙўйҹід№җ');
					return;
				}
				
				// жҳҫзӨәеҠ иҪҪжҸҗзӨә
				uni.showLoading({
					title: 'жҗңзҙўдёӯ...'
				});
				
				this.isSearching = true;
				this.hasSearched = true;
				
				// йҮҚзҪ®еҲҶйЎөе’Ңз»“жһң
				this.resetSearchState();
				
				try {
					// е°Ҷжҗңзҙўе…ій”®иҜҚдҝқеӯҳеҲ°еҺҶеҸІи®°еҪ•
					this.saveSearchHistory(this.searchText.trim());
					
					console.log('ејҖе§Ӣжҗңзҙўпјҡ', this.searchText.trim());
					
					// е№¶иЎҢеҠ иҪҪеҗ„зұ»еһӢз»“жһңзҡ„з¬¬дёҖйЎө
					await Promise.all([
						this.searchByType(1), // еҚ•жӣІ
						this.searchByType(100), // жӯҢжүӢ
						this.searchByType(10), // дё“иҫ‘
						this.searchByType(1006) // жӯҢиҜҚ
					]);
					
					// иҮӘеҠЁеҲҮжҚўеҲ°жңүз»“жһңзҡ„ж ҮзӯҫйЎө
					this.autoSwitchToTabWithResults();
					
				} catch (error) {
					console.error('жҗңзҙўеӨұиҙҘпјҡ', error);
					uni.showToast({
						title: 'жҗңзҙўеӨұиҙҘпјҢиҜ·йҮҚиҜ•',
						icon: 'none'
					});
				} finally {
					// йҡҗи—ҸеҠ иҪҪжҸҗзӨә
					uni.hideLoading();
					this.isSearching = false;
				}
			},
			
			// йҮҚзҪ®жҗңзҙўзҠ¶жҖҒ
			resetSearchState() {
				this.searchResults = {
					songs: [],
					artists: [],
					albums: [],
					lyrics: []
				};
				
				this.pageOffset = {
					songs: 0,
					artists: 0,
					albums: 0,
					lyrics: 0
				};
				
				this.hasMore = {
					songs: false,
					artists: false,
					albums: false,
					lyrics: false
				};
				
				this.isLoadingMore = {
					songs: false,
					artists: false,
					albums: false,
					lyrics: false
				};
				
				this.totalCount = {
					songs: 0,
					artists: 0,
					albums: 0,
					lyrics: 0
				};
				
				// йҮҚзҪ®ж Үзӯҫж•°йҮҸ
				this.tabs.forEach(tab => tab.count = 0);
			},
			
			// ж №жҚ®зұ»еһӢжҗңзҙў
			async searchByType(type) {
				try {
					// зЎ®е®ҡжҗңзҙўзұ»еһӢеҜ№еә”зҡ„з»“жһңзұ»еҲ«
					const resultKey = this.getResultKeyByType(type);
					if (!resultKey) return;
					
					// иҺ·еҸ–еҪ“еүҚзұ»еһӢзҡ„еҒҸз§»йҮҸ
					const offset = this.pageOffset[resultKey];
					
					// жү§иЎҢжҗңзҙў
					const results = await searchMusic(this.searchText.trim(), {
						type: type,
						limit: this.pageSize,
						offset: offset
					});
					
					if (!results) {
						console.error(`жҗңзҙўзұ»еһӢ${type}иҝ”еӣһз»“жһңдёәз©ә`);
						return;
					}
					
					console.log(`жҗңзҙўзұ»еһӢ${type}иҝ”еӣһз»“жһң:`, results);
					
					// й’ҲеҜ№дёҚеҗҢзұ»еһӢзҡ„з»“жһңиҝӣиЎҢеӨ„зҗҶ
					let items = [];
					let total = 0;
					
					// жЈҖжҹҘжҳҜеҗҰиҝ”еӣһзҡ„жҳҜж–°APIж јејҸзҡ„з»“жһң
					if (results[resultKey] && Array.isArray(results[resultKey])) {
						// ж–°APIж јејҸпјҢзӣҙжҺҘдҪҝз”Ёиҝ”еӣһзҡ„з»“жһң
						items = results[resultKey];
						total = results.totalCount ? results.totalCount[resultKey] || 0 : 0;
					} else {
						// ж—§APIж јејҸпјҢж №жҚ®дёҚеҗҢзұ»еһӢиҺ·еҸ–з»“жһңе’ҢжҖ»ж•°
						switch(type) {
							case 1: // жӯҢжӣІ
								if (results.result && results.result.songs) {
									items = results.result.songs.map(song => ({
										id: song.id,
										name: song.name,
										artist: song.artists ? song.artists.map(a => a.name).join('/') : 'жңӘзҹҘжӯҢжүӢ',
										album: song.album ? song.album.name : 'жңӘзҹҘдё“иҫ‘',
										cover: song.album && song.album.picUrl ? song.album.picUrl : '/static/music-cover.png',
										duration: song.duration || 0
									}));
									total = results.result.songCount || 0;
								}
								break;
							case 100: // жӯҢжүӢ
								if (results.result && results.result.artists) {
									items = results.result.artists.map(artist => ({
										id: artist.id,
										name: artist.name,
										avatar: artist.picUrl || '/static/music-cover.png'
									}));
									total = results.result.artistCount || 0;
								}
								break;
							case 10: // дё“иҫ‘
								if (results.result && results.result.albums) {
									items = results.result.albums.map(album => ({
										id: album.id,
										name: album.name,
										artist: album.artist ? album.artist.name : 'жңӘзҹҘжӯҢжүӢ',
										cover: album.picUrl || '/static/music-cover.png'
									}));
									total = results.result.albumCount || 0;
								}
								break;
							case 1006: // жӯҢиҜҚ
								if (results.result && results.result.songs) {
									items = results.result.songs.map(song => ({
										id: song.id,
										name: song.name,
										artist: song.artists ? song.artists.map(a => a.name).join('/') : 'жңӘзҹҘжӯҢжүӢ',
										lyrics: song.lyrics || song.snippet || 'жҡӮж— жӯҢиҜҚ',
										album: song.album ? song.album.name : 'жңӘзҹҘдё“иҫ‘',
										cover: song.album && song.album.picUrl ? song.album.picUrl : '/static/music-cover.png'
									}));
									total = results.result.songCount || 0;
								}
								break;
						}
					}
					
					// жӣҙж–°еҜ№еә”зұ»еһӢзҡ„з»“жһң
					if (offset === 0) {
						// з¬¬дёҖйЎөпјҢзӣҙжҺҘжӣҝжҚў
						this.searchResults[resultKey] = items;
					} else {
						// еҗҺз»ӯйЎөпјҢиҝҪеҠ з»“жһң
						this.searchResults[resultKey] = [...this.searchResults[resultKey], ...items];
					}
					
					// жӣҙж–°и®Ўж•°е’ҢеҲҶйЎөзҠ¶жҖҒ
					this.totalCount[resultKey] = total;
					
					// жӣҙж–°ж ҮзӯҫйЎөжҳҫзӨәзҡ„и®Ўж•°
					const tabIndex = this.getTabIndexByResultKey(resultKey);
					if (tabIndex >= 0) {
						this.tabs[tabIndex].count = this.totalCount[resultKey];
					}
					
					// еҲӨж–ӯжҳҜеҗҰиҝҳжңүжӣҙеӨҡз»“жһң
					this.hasMore[resultKey] = this.searchResults[resultKey].length < this.totalCount[resultKey];
					
					// жӣҙж–°еҒҸз§»йҮҸ
					this.pageOffset[resultKey] = this.searchResults[resultKey].length;
					
					console.log(`[${resultKey}] е·ІеҠ иҪҪ: ${this.searchResults[resultKey].length}, жҖ»ж•°: ${this.totalCount[resultKey]}, иҝҳжңүжӣҙеӨҡ: ${this.hasMore[resultKey]}`);
					
				} catch (error) {
					console.error(`жҗңзҙў${type}зұ»еһӢеӨұиҙҘ:`, error);
				}
			},
			
			// ж №жҚ®жҗңзҙўзұ»еһӢиҺ·еҸ–з»“жһңй”®еҗҚ
			getResultKeyByType(type) {
				switch (type) {
					case 1: return 'songs';
					case 100: return 'artists';
					case 10: return 'albums';
					case 1006: return 'lyrics';
					default: return null;
				}
			},
			
			// ж №жҚ®з»“жһңй”®еҗҚиҺ·еҸ–ж ҮзӯҫйЎөзҙўеј•
			getTabIndexByResultKey(resultKey) {
				switch (resultKey) {
					case 'songs': return 0;
					case 'artists': return 1;
					case 'albums': return 2;
					case 'lyrics': return 3;
					default: return -1;
				}
			},
			
			// иҮӘеҠЁеҲҮжҚўеҲ°жңүз»“жһңзҡ„ж ҮзӯҫйЎө
			autoSwitchToTabWithResults() {
				// дјҳе…ҲдҝқжҢҒеҪ“еүҚж ҮзӯҫйЎөпјҢеҰӮжһңеҪ“еүҚж ҮзӯҫйЎөжңүз»“жһң
				const currentKey = ['songs', 'artists', 'albums', 'lyrics'][this.currentTab];
				if (this.searchResults[currentKey] && this.searchResults[currentKey].length > 0) {
					return;
				}
				
				// еҗҰеҲҷеҲҮжҚўеҲ°з¬¬дёҖдёӘжңүз»“жһңзҡ„ж ҮзӯҫйЎө
				if (this.searchResults.songs.length > 0) {
					this.currentTab = 0;
				} else if (this.searchResults.artists.length > 0) {
					this.currentTab = 1;
				} else if (this.searchResults.albums.length > 0) {
					this.currentTab = 2;
				} else if (this.searchResults.lyrics.length > 0) {
					this.currentTab = 3;
				}
			},
			
			// еҠ иҪҪжӣҙеӨҡжӯҢжӣІ
			async loadMoreSongs() {
				// жЈҖжҹҘжҳҜеҗҰдёәжёёе®ўжЁЎејҸ
				if (isInGuestMode()) {
					showGuestModeLimit('жҗңзҙўжӣҙеӨҡеҶ…е®№');
					return;
				}
				
				if (!this.hasMore.songs || this.isLoadingMore.songs) return;
				
				console.log('еҠ иҪҪжӣҙеӨҡжӯҢжӣІ');
				this.isLoadingMore.songs = true;
				
				try {
					await this.searchByType(1);
				} finally {
					this.isLoadingMore.songs = false;
				}
			},
			
			// еҠ иҪҪжӣҙеӨҡжӯҢжүӢ
			async loadMoreArtists() {
				// жЈҖжҹҘжҳҜеҗҰдёәжёёе®ўжЁЎејҸ
				if (isInGuestMode()) {
					showGuestModeLimit('жҗңзҙўжӣҙеӨҡеҶ…е®№');
					return;
				}
				
				if (!this.hasMore.artists || this.isLoadingMore.artists) return;
				
				console.log('еҠ иҪҪжӣҙеӨҡжӯҢжүӢ');
				this.isLoadingMore.artists = true;
				
				try {
					await this.searchByType(100);
				} finally {
					this.isLoadingMore.artists = false;
				}
			},
			
			// еҠ иҪҪжӣҙеӨҡдё“иҫ‘
			async loadMoreAlbums() {
				// жЈҖжҹҘжҳҜеҗҰдёәжёёе®ўжЁЎејҸ
				if (isInGuestMode()) {
					showGuestModeLimit('жҗңзҙўжӣҙеӨҡеҶ…е®№');
					return;
				}
				
				if (!this.hasMore.albums || this.isLoadingMore.albums) return;
				
				console.log('еҠ иҪҪжӣҙеӨҡдё“иҫ‘');
				this.isLoadingMore.albums = true;
				
				try {
					await this.searchByType(10);
				} finally {
					this.isLoadingMore.albums = false;
				}
			},
			
			// еҠ иҪҪжӣҙеӨҡжӯҢиҜҚ
			async loadMoreLyrics() {
				// жЈҖжҹҘжҳҜеҗҰдёәжёёе®ўжЁЎејҸ
				if (isInGuestMode()) {
					showGuestModeLimit('жҗңзҙўжӣҙеӨҡеҶ…е®№');
					return;
				}
				
				if (!this.hasMore.lyrics || this.isLoadingMore.lyrics) return;
				
				console.log('еҠ иҪҪжӣҙеӨҡжӯҢиҜҚ');
				this.isLoadingMore.lyrics = true;
				
				try {
					await this.searchByType(1006);
				} finally {
					this.isLoadingMore.lyrics = false;
				}
			},
			
			// еҲҮжҚўж ҮзӯҫйЎө
			switchTab(index) {
				this.currentTab = index
			},
			
			// иҝ”еӣһ
			goBack() {
				uni.navigateBack()
			},
			
			// ж’ӯж”ҫжӯҢжӣІ
			async playSong(song) {
				// жЈҖжҹҘжҳҜеҗҰдёәжёёе®ўжЁЎејҸ
				if (isInGuestMode()) {
					showGuestModeLimit('ж’ӯж”ҫжӯҢжӣІ');
					return;
				}
				
				try {
					// жҳҫзӨәеҠ иҪҪжҸҗзӨә
					uni.showLoading({
						title: 'еҠ иҪҪдёӯ...'
					})
					
					// жһ„е»әе®Ңж•ҙзҡ„жӯҢжӣІдҝЎжҒҜ
					let fullSongInfo = song;
					
					// еҰӮжһңжҳҜд»ҺжӯҢиҜҚжҗңзҙўз»“жһңж’ӯж”ҫзҡ„пјҢеҸҜиғҪйңҖиҰҒиЎҘе……дёҖдәӣеӯ—ж®ө
					if (this.currentTab === 3 && !song.duration) {
						try {
							// е°қиҜ•иҺ·еҸ–е®Ңж•ҙзҡ„жӯҢжӣІдҝЎжҒҜ
							const songDetail = await getMusicById(song.id);
							if (songDetail) {
								fullSongInfo = {
									...song,
									duration: songDetail.duration || 0,
									// иЎҘе……е…¶д»–еҸҜиғҪзјәеӨұзҡ„еӯ—ж®ө
									artist: songDetail.artist || song.artist,
									album: songDetail.album || song.album,
									cover: songDetail.cover || song.cover || '/static/music-cover.png'
								};
							}
						} catch (err) {
							console.warn('иҺ·еҸ–е®Ңж•ҙжӯҢжӣІдҝЎжҒҜеӨұиҙҘпјҢдҪҝз”ЁзҺ°жңүдҝЎжҒҜ', err);
						}
					}
					
					// иҺ·еҸ–жӯҢжӣІURL
					const url = await getMusicUrl(fullSongInfo.id);
					if (!url) {
						throw new Error('иҺ·еҸ–жӯҢжӣІURLеӨұиҙҘ');
					}
					
					// жӣҙж–°жӯҢжӣІеҜ№иұЎ
					const playSong = {
						...fullSongInfo,
						url: url
					};
					
					// иҺ·еҸ–еҪ“еүҚж’ӯж”ҫеҲ—иЎЁ
					let playList = [];
					try {
						const playListStr = uni.getStorageSync('playList');
						if (playListStr) {
							playList = JSON.parse(playListStr);
							if (!Array.isArray(playList)) {
								console.warn('ж’ӯж”ҫеҲ—иЎЁдёҚжҳҜж•°з»„пјҢйҮҚзҪ®дёәз©әж•°з»„');
								playList = [];
							}
						}
					} catch (e) {
						console.error('и§Јжһҗж’ӯж”ҫеҲ—иЎЁеӨұиҙҘпјҡ', e);
						playList = [];
					}
					
					// жЈҖжҹҘжӯҢжӣІжҳҜеҗҰе·ІеңЁж’ӯж”ҫеҲ—иЎЁдёӯ
					const index = playList.findIndex(item => item.id === fullSongInfo.id);
					let currentIndex = index;
					
					if (index === -1) {
						// еҰӮжһңдёҚеңЁеҲ—иЎЁдёӯпјҢж·»еҠ еҲ°еҲ—иЎЁ
						playList.push(playSong);
						currentIndex = playList.length - 1;
					} else {
						// еҰӮжһңеңЁеҲ—иЎЁдёӯпјҢжӣҙж–°дҝЎжҒҜ
						playList[index] = {
							...playList[index],
							...playSong
						};
					}
					
					// еӯҳеӮЁеҪ“еүҚж’ӯж”ҫжӯҢжӣІдҝЎжҒҜ
					uni.setStorageSync('currentSong', JSON.stringify(playSong));
					// еӯҳеӮЁж’ӯж”ҫеҲ—иЎЁ
					uni.setStorageSync('playList', JSON.stringify(playList));
					// еӯҳеӮЁеҪ“еүҚж’ӯж”ҫзҙўеј•
					uni.setStorageSync('currentIndex', currentIndex);
					// еӯҳеӮЁиҮӘеҠЁж’ӯж”ҫж Үеҝ—
					uni.setStorageSync('autoPlay', 'true');
					
					// и·іиҪ¬еҲ°ж’ӯж”ҫеҷЁйЎөйқў
					uni.switchTab({
						url: '/pages/player/player'
					});
				} catch (error) {
					console.error('ж’ӯж”ҫеӨұиҙҘпјҡ', error);
					uni.showToast({
						title: error.message || 'ж’ӯж”ҫеӨұиҙҘпјҢиҜ·йҮҚиҜ•',
						icon: 'none'
					});
				} finally {
					uni.hideLoading();
				}
			},
			
			// жҹҘзңӢжӯҢжүӢиҜҰжғ…
			viewArtist(artist) {
				uni.navigateTo({
					url: `/pages/artist/artist?id=${artist.id}&name=${encodeURIComponent(artist.name)}`
				})
			},
			
			// жҹҘзңӢдё“иҫ‘иҜҰжғ…
			viewAlbum(album) {
				uni.navigateTo({
					url: `/pages/album/album?id=${album.id}&name=${encodeURIComponent(album.name)}`
				})
			},
			
			// еӨ„зҗҶжӯҢжӣІзӮ№еҮ»
			handleSongTap(song) {
				if (this.fromPlaylist) {
					this.addSongToPlaylist(song);
				} else {
					this.playSong(song);
				}
			},
			
			// жөӢиҜ•ж·»еҠ жӯҢжӣІеҲ°ж’ӯж”ҫеҲ—иЎЁ
			testAddSong(song, event) {
				console.log("жөӢиҜ•ж·»еҠ жӯҢжӣІеҲ°ж’ӯж”ҫеҲ—иЎЁпјҢжӯҢжӣІдҝЎжҒҜ:", song);
				console.log("жөӢиҜ•ж·»еҠ жӯҢжӣІеҲ°ж’ӯж”ҫеҲ—иЎЁпјҢдәӢд»¶еҜ№иұЎ:", event);
				console.log("fromPlaylistзҠ¶жҖҒ:", this.fromPlaylist);
				console.log("playlistId:", this.playlistId);
				uni.showToast({
					title: 'жөӢиҜ•зӮ№еҮ»ж·»еҠ жӯҢжӣІ',
					icon: 'none'
				});
			},
			
			// ж·»еҠ жӯҢжӣІеҲ°ж’ӯж”ҫеҲ—иЎЁ
			async addSongToPlaylist(song) {
				if (this.addingToPlaylist) return
				
				console.log("еҮҶеӨҮж·»еҠ жӯҢжӣІеҲ°жӯҢеҚ•пјҢжӯҢжӣІдҝЎжҒҜ:", song);
				console.log("еҪ“еүҚжӯҢеҚ•ID:", this.playlistId);
				
				if (!this.playlistId) {
					uni.showToast({
						title: 'жӯҢеҚ•IDж— ж•Ҳ',
						icon: 'none'
					});
					return;
				}
				
				// и®ҫзҪ®еҪ“еүҚжӯҢжӣІзҡ„ж·»еҠ дёӯзҠ¶жҖҒ
				this.$set(song, 'isAdding', true);
				
				// жҳҫзӨәеҠ иҪҪжҸҗзӨә
				uni.showLoading({
					title: 'ж·»еҠ дёӯ...'
				})
				
				this.addingToPlaylist = true
				
				try {
					// еҜје…Ҙж’ӯж”ҫеҲ—иЎЁзј“еӯҳе·Ҙе…·
					const { addSongsToPlaylist } = require('@/utils/playlistCache.js');
					const userId = uni.getStorageSync('userId') || '';
					
					// зЎ®дҝқжүҖжңүеҝ…иҰҒзҡ„еӯ—ж®өйғҪеӯҳеңЁ
					const songData = {
						id: song.id,
						name: song.name || 'жңӘзҹҘжӯҢжӣІ',
						artist: song.artist || 'жңӘзҹҘжӯҢжүӢ',
						album: song.album || 'жңӘзҹҘдё“иҫ‘',
						duration: song.duration || 0,
						cover: song.cover || '/static/music-cover.png',
						// зЎ®дҝқи®ҫзҪ®URL
						url: song.url || `https://music.163.com/song/media/outer/url?id=${song.id}.mp3`
					};
					
					console.log('еӨ„зҗҶеҗҺзҡ„жӯҢжӣІж•°жҚ®:', songData);
					
					// жһ„е»әиҜ·жұӮURLе’Ңж•°жҚ®
					const baseUrl = apiConfig.playlist.baseUrl;
					const endpoint = apiConfig.playlist.addSong(this.playlistId);
					const url = `${baseUrl}${endpoint}`;
					
					// еҢ…иЈ…жҲҗеҗҺз«Ҝжңҹжңӣзҡ„ж јејҸ
					const requestData = {
						songs: [songData]
					};
					
					// е…Ҳжӣҙж–°жң¬ең°зј“еӯҳ
					const localSuccess = addSongsToPlaylist(this.playlistId, songData, userId);
					if (localSuccess) {
						console.log('жҲҗеҠҹжӣҙж–°жң¬ең°ж’ӯж”ҫеҲ—иЎЁзј“еӯҳ');
					}
					
					// з„¶еҗҺеҗҢжӯҘеҲ°жңҚеҠЎеҷЁ
					console.log("ж·»еҠ жӯҢжӣІж•°жҚ®:", JSON.stringify(requestData));
					const response = await request(url, 'POST', requestData);
					
					console.log("ж·»еҠ жӯҢжӣІе“Қеә”:", response);
					
					if (response.code === 200) {
						uni.hideLoading();
						uni.showToast({
							title: 'е·Іж·»еҠ еҲ°жӯҢеҚ•',
							icon: 'success'
						});
						
						// д»Һжҗңзҙўз»“жһңдёӯз§»йҷӨе·Іж·»еҠ зҡ„жӯҢжӣІ
						this.searchResults.songs = this.searchResults.songs.filter(s => s.id !== song.id);
						
						// е»¶иҝҹеҗҺиҝ”еӣһж’ӯж”ҫеҲ—иЎЁйЎө
						setTimeout(() => {
							uni.navigateBack();
						}, 1500);
					} else {
						// еҚідҪҝжңҚеҠЎеҷЁз«ҜеӨұиҙҘпјҢз”ұдәҺе·Із»Ҹжӣҙж–°дәҶжң¬ең°зј“еӯҳпјҢд»Қз„¶еҸҜд»ҘжҳҫзӨәжҲҗеҠҹ
						if (localSuccess) {
							uni.hideLoading();
							uni.showToast({
								title: 'е·Іж·»еҠ еҲ°жң¬ең°жӯҢеҚ•',
								icon: 'success'
							});
							
							// д»Һжҗңзҙўз»“жһңдёӯз§»йҷӨе·Іж·»еҠ зҡ„жӯҢжӣІ
							this.searchResults.songs = this.searchResults.songs.filter(s => s.id !== song.id);
							
							// е»¶иҝҹеҗҺиҝ”еӣһж’ӯж”ҫеҲ—иЎЁйЎө
							setTimeout(() => {
								uni.navigateBack();
							}, 1500);
						} else {
							throw new Error(response.message || 'ж·»еҠ жӯҢжӣІеӨұиҙҘ');
						}
					}
				} catch (error) {
					console.error('ж·»еҠ жӯҢжӣІеӨұиҙҘ:', error);
					uni.hideLoading();
					uni.showToast({
						title: error.message || 'ж·»еҠ жӯҢжӣІеӨұиҙҘ',
						icon: 'none'
					});
				} finally {
					this.addingToPlaylist = false;
					// еҰӮжһңиҝҳеңЁз»“жһңеҲ—иЎЁдёӯпјҢеҸ–ж¶Ҳж·»еҠ дёӯзҠ¶жҖҒ
					const songInList = this.searchResults.songs.find(s => s.id === song.id);
					if (songInList) {
						this.$set(songInList, 'isAdding', false);
					}
				}
			}
		}
	}
</script>

